export type RaylibSymbols = typeof symbolDefinitions;

export type StructBytes<T = unknown> = Uint8Array<ArrayBufferLike>;
export type CStringLike = string | CStringPointer;
export type StructLike<T> = T | StructBytes<T>;

function coerceCStringLike(value: CStringLike): CStringPointer {
  return typeof value === "string" ? cstr(value) : value;
}

function coerceStructLike<T>(
  value: StructLike<T>,
  structDef: { toBytes(value: T): Uint8Array },
): StructBytes<T> {
  return value instanceof Uint8Array ? value as StructBytes<T> : structDef.toBytes(value as T);
}

